export class EnvironmentBuilder {
  private world: World;
  private starfield: Points | null = null;
  private gridPulseTime = 0;
  private gridLines: LineSegments | null = null;
  private ambientOrbs: Mesh[] = [];
  private dynamicPointLights: PointLight[] = [];
  private currentThemeIndex = -1;

  // Keep references for theme switching
  private themeGroup: Group;
  private gridGroup: Group;
  private starfieldGroup: Group;

  constructor(world: World) {
    this.world = world;
    this.themeGroup = new Group();
    this.gridGroup = new Group();
    this.starfieldGroup = new Group();
    world.scene.add(this.themeGroup);
    world.scene.add(this.gridGroup);
    world.scene.add(this.starfieldGroup);
  }

  build() {
    const scene = this.world.scene;

    // Base lighting (constant across themes)
    const ambient = new AmbientLight(0x112233, 0.4);
    scene.add(ambient);

    const dirLight = new DirectionalLight(0x4488cc, 0.6);
    dirLight.position.set(5, 10, 5);
    scene.add(dirLight);

    // Build ground plane (constant)
    const gridSize = 40;
    const groundGeo = new PlaneGeometry(gridSize, gridSize);
    const groundMat = new MeshStandardMaterial({
      color: 0x000a11,
      roughness: 1,
      metalness: 0,
    });
    const ground = new Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.02;
    scene.add(ground);

    // Apply default theme
    this.applyTheme(0);
  }

  applyTheme(courseIndex: number) {
    if (courseIndex === this.currentThemeIndex) return;
    this.currentThemeIndex = courseIndex;
    const theme = COURSE_THEMES[courseIndex] || COURSE_THEMES[0];

    // Clear previous theme elements
    this.clearThemeElements();

    // Fog
    this.world.scene.fog = new Fog(theme.fogColor, 10, 80);

    // Grid
    this.buildGrid(theme);

    // Starfield
    this.buildStarfield(theme);

    // Ambient geometry
    this.buildAmbientGeometry(theme);

    // Point lights
    for (const lightDef of theme.pointLights) {
      const light = new PointLight(lightDef.color, lightDef.intensity, 20);
      light.position.set(lightDef.pos[0], lightDef.pos[1], lightDef.pos[2]);
      this.themeGroup.add(light);
      this.dynamicPointLights.push(light);
    }
  }

  private clearThemeElements() {
    // Clear grid
    while (this.gridGroup.children.length > 0) {
      const child = this.gridGroup.children[0];
      this.gridGroup.remove(child);
    }
    this.gridLines = null;

    // Clear starfield
    while (this.starfieldGroup.children.length > 0) {
      const child = this.starfieldGroup.children[0];
      this.starfieldGroup.remove(child);
    }
    this.starfield = null;

    // Clear theme decorations
    while (this.themeGroup.children.length > 0) {
      const child = this.themeGroup.children[0];
      this.themeGroup.remove(child);
    }
    this.ambientOrbs = [];
    this.dynamicPointLights = [];
  }

  private buildGrid(theme: CourseTheme) {
    const gridSize = 40;
    const divisions = 40;
    const step = gridSize / divisions;
    const halfSize = gridSize / 2;

    const vertices: number[] = [];
    for (let i = 0; i <= divisions; i++) {
      const pos = -halfSize + i * step;
      vertices.push(pos, -0.01, -halfSize, pos, -0.01, halfSize);
      vertices.push(-halfSize, -0.01, pos, halfSize, -0.01, pos);
    }

    const geo = new BufferGeometry();
    geo.setAttribute("position", new Float32BufferAttribute(vertices, 3));

    const mat = new LineBasicMaterial({
      color: theme.gridColor,
      transparent: true,
      opacity: theme.gridOpacity,
    });

    this.gridLines = new LineSegments(geo, mat);
    this.gridGroup.add(this.gridLines);
  }

  private buildStarfield(theme: CourseTheme) {
    const count = 2000;
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);

    for (let i = 0; i < count; i++) {
      const i3 = i * 3;
      const r = 30 + Math.random() * 50;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.random() * Math.PI;

      positions[i3] = r * Math.sin(phi) * Math.cos(theta);
      positions[i3 + 1] = Math.abs(r * Math.cos(phi)) + 2;
      positions[i3 + 2] = r * Math.sin(phi) * Math.sin(theta);

      const colorSet = theme.starColors[Math.floor(Math.random() * theme.starColors.length)];
      colors[i3] = colorSet[0];
      colors[i3 + 1] = colorSet[1];
      colors[i3 + 2] = colorSet[2];
    }

    const geo = new BufferGeometry();
    geo.setAttribute("position", new Float32BufferAttribute(positions, 3));
    geo.setAttribute("color", new Float32BufferAttribute(colors, 3));

    const mat = new PointsMaterial({
      size: 0.15,
      vertexColors: true,
      transparent: true,
      opacity: 0.8,
      blending: AdditiveBlending,
      sizeAttenuation: true,
    });

    this.starfield = new Points(geo, mat);
    this.starfieldGroup.add(this.starfield);
  }

  private buildAmbientGeometry(theme: CourseTheme) {
    for (const s of theme.ambientShapes) {
      let geo: any;
      switch (s.geo) {
        case "sphere":
          geo = new SphereGeometry(s.size, 12, 12);
          break;
        case "cone":
          geo = new ConeGeometry(s.size * 0.6, s.size * 1.2, 6);
          break;
        case "torus":
          geo = new TorusGeometry(s.size, s.size * 0.2, 8, 16);
          break;
        default:
          geo = new BoxGeometry(s.size, s.size, s.size);
      }

      const mat = new MeshBasicMaterial({
        color: s.color,
        transparent: true,
        opacity: 0.08,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.position.set(s.pos[0], s.pos[1], s.pos[2]);

      const edges = new EdgesGeometry(geo);
      const edgeMat = new LineBasicMaterial({
        color: s.color,
        transparent: true,
        opacity: 0.3,
      });
      mesh.add(new LineSegments(edges, edgeMat));

      (mesh as any).__rotSpeed = s.speed;
      this.ambientOrbs.push(mesh);
      this.themeGroup.add(mesh);
    }
  }

  update(dt: number) {
    // Rotate ambient geometry
    for (const orb of this.ambientOrbs) {
      const speed = (orb as any).__rotSpeed || 0.2;
      orb.rotation.x += speed * dt * 0.5;
      orb.rotation.y += speed * dt;
    }

    // Grid pulse
    if (this.gridLines) {
      this.gridPulseTime += dt;
      const pulse = 0.3 + Math.sin(this.gridPulseTime * 0.5) * 0.1;
      (this.gridLines.material as LineBasicMaterial).opacity = pulse;
    }

    // Slow starfield rotation
    if (this.starfield) {
      this.starfield.rotation.y += dt * 0.005;
    }
  }
}

/**
 * Holo Golf VR — Ball Controller
 * Custom physics for the golf ball: velocity, friction, slope, walls,
 * bumper/obstacle collision, hole capture, and trail effects.
 */
import {
  World,
  Vector3,
  Mesh,
  SphereGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Group,
  Color,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  AdditiveBlending,
  PointLight,
  RingGeometry,
  DoubleSide,
} from "@iwsdk/core";
import { AudioManager } from "./audio";

const BALL_RADIUS = 0.025;
const FRICTION = 0.97;
const SLOPE_FORCE = 4.0;
const MIN_VELOCITY = 0.005;
const MAX_VELOCITY = 12.0;
const WALL_BOUNCE = 0.65;
const BUMPER_BOUNCE = 1.8;
const GRAVITY = -9.8;

export interface BumperCollider {
  position: Vector3;
  radius: number;
  mesh?: any;
}

export interface ObstacleCollider {
  type: "windmill_arm" | "moving_wall";
  mesh: any;
  getWorldBounds: () => { min: Vector3; max: Vector3; normal: Vector3 };
}

export class BallController {
  position = new Vector3(0, 0.05, 0);
  velocity = new Vector3(0, 0, 0);
  isActive = false;
  private mesh: Mesh;
  private glowMesh: Mesh;
  private trailGroup: Group;
  private light: PointLight;
  private world: World;
  private audio: AudioManager;
  private sinking = false;
  private sinkTarget = new Vector3();
  private sinkTimer = 0;
  private trailPositions: Vector3[] = [];
  private trailPool: Mesh[] = [];
  private trailActiveCount = 0;
  private bounceCount = 0;
  private onFloor = true;
  private floorY = 0.05;
  private stopped = true;

  // Special zone effects
  private windForce = new Vector3();
  private frictionOverride: number | null = null;

  constructor(world: World, audio: AudioManager) {
    this.world = world;
    this.audio = audio;

    // Main ball mesh — glowing cyan sphere
    const ballGeo = new SphereGeometry(BALL_RADIUS, 16, 16);
    const ballMat = new MeshStandardMaterial({
      color: new Color(0x00ffff),
      emissive: new Color(0x00aaaa),
      emissiveIntensity: 1.5,
      metalness: 0.3,
      roughness: 0.1,
    });
    this.mesh = new Mesh(ballGeo, ballMat);

    // Wireframe glow
    const edgesGeo = new EdgesGeometry(ballGeo);
    this.glowMesh = new Mesh(); // placeholder
    const wireframe = new LineSegments(
      edgesGeo,
      new LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.6 }),
    );
    this.mesh.add(wireframe);

    // Outer glow
    const glowGeo = new SphereGeometry(BALL_RADIUS * 1.6, 12, 12);
    const glowMat = new MeshBasicMaterial({
      color: new Color(0x00ffff),
      transparent: true,
      opacity: 0.15,
      blending: AdditiveBlending,
    });
    this.glowMesh = new Mesh(glowGeo, glowMat);
    this.mesh.add(this.glowMesh);

    // Ground ring indicator
    const ringGeo = new RingGeometry(BALL_RADIUS * 1.5, BALL_RADIUS * 2.5, 24);
    const ringMat = new MeshBasicMaterial({
      color: 0x00ffff,
      transparent: true,
      opacity: 0.3,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    const ring = new Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = -BALL_RADIUS + 0.001;
    this.mesh.add(ring);

    // Point light
    this.light = new PointLight(0x00ffff, 0.8, 3);
    this.mesh.add(this.light);

    // Trail group + pre-allocated pool
    this.trailGroup = new Group();
    world.scene.add(this.trailGroup);
    this.initTrailPool(50);

    world.scene.add(this.mesh);
    this.mesh.visible = false;
  }

  reset(pos: Vector3) {
    this.position.copy(pos);
    this.position.y = pos.y + BALL_RADIUS;
    this.velocity.set(0, 0, 0);
    this.mesh.position.copy(this.position);
    this.mesh.visible = true;
    this.mesh.scale.setScalar(1);
    this.isActive = true;
    this.sinking = false;
    this.stopped = true;
    this.bounceCount = 0;
    this.floorY = pos.y + BALL_RADIUS;
    this.windForce.set(0, 0, 0);
    this.frictionOverride = null;
    this.clearTrail();
  }

  hit(direction: Vector3, power: number) {
    if (!this.isActive || this.sinking) return;
    const force = direction.clone().normalize().multiplyScalar(power);
    force.y = Math.max(force.y, power * 0.05); // tiny upward lift
    this.velocity.copy(force);
    this.stopped = false;
    this.bounceCount = 0;
  }

  sinkIntoHole(holePos: Vector3) {
    this.sinking = true;
    this.sinkTarget.copy(holePos);
    this.sinkTarget.y -= 0.1;
    this.sinkTimer = 0;
    this.velocity.set(0, 0, 0);
  }

  isStopped(): boolean {
    return this.stopped && !this.sinking;
  }

  setWindForce(force: Vector3) {
    this.windForce.copy(force);
  }

  setFrictionOverride(friction: number | null) {
    this.frictionOverride = friction;
  }

  update(dt: number) {
    if (!this.isActive) return;

    if (this.sinking) {
      this.sinkTimer += dt;
      const t = Math.min(this.sinkTimer / 0.5, 1);
      this.position.lerp(this.sinkTarget, t * 0.15);
      const scale = 1 - t * 0.8;
      this.mesh.scale.setScalar(Math.max(scale, 0.01));
      this.mesh.position.copy(this.position);
      if (t >= 1) {
        this.mesh.visible = false;
        this.isActive = false;
      }
      return;
    }

    if (this.stopped) {
      this.mesh.position.copy(this.position);
      return;
    }

    // Apply friction (use override if in special zone)
    const fric = this.frictionOverride ?? FRICTION;
    this.velocity.x *= fric;
    this.velocity.z *= fric;

    // Apply wind force
    if (this.windForce.lengthSq() > 0) {
      this.velocity.add(this.windForce.clone().multiplyScalar(dt));
    }

    // Gravity
    if (!this.onFloor) {
      this.velocity.y += GRAVITY * dt;
    }

    // Clamp velocity
    const speed = this.velocity.length();
    if (speed > MAX_VELOCITY) {
      this.velocity.normalize().multiplyScalar(MAX_VELOCITY);
    }

    // Move ball
    this.position.add(this.velocity.clone().multiplyScalar(dt));

    // Floor collision
    if (this.position.y <= this.floorY) {
      this.position.y = this.floorY;
      if (this.velocity.y < -0.3) {
        this.velocity.y *= -WALL_BOUNCE * 0.5;
        this.bounceCount++;
        if (this.bounceCount > 3) {
          this.velocity.y = 0;
        }
        this.audio.playBounce(Math.abs(this.velocity.y));
      } else {
        this.velocity.y = 0;
      }
      this.onFloor = true;
    } else {
      this.onFloor = false;
    }

    // Wall collisions
    this.checkWallCollisions();

    // Bumper collisions
    this.checkBumperCollisions();

    // Check if ball fell off course
    if (this.position.y < -5) {
      this.velocity.set(0, 0, 0);
      this.stopped = true;
    }

    // Stop check
    if (speed < MIN_VELOCITY && this.onFloor) {
      this.velocity.set(0, 0, 0);
      this.stopped = true;
    }

    // Update mesh
    this.mesh.position.copy(this.position);

    // Glow pulse
    const pulse = 0.12 + Math.sin(performance.now() * 0.004) * 0.05;
    (this.glowMesh.material as MeshBasicMaterial).opacity = pulse;
    this.light.intensity = 0.5 + speed * 0.3;

    // Update trail (optimized pool)
    this.updateTrail();
  }

  private checkWallCollisions() {
    const walls = (this.world as any).__holoGolfWalls as Array<{
      normal: Vector3;
      point: Vector3;
      min: Vector3;
      max: Vector3;
    }>;
    if (!walls) return;

    for (const wall of walls) {
      const dist = this.position.clone().sub(wall.point).dot(wall.normal);
      if (dist < BALL_RADIUS) {
        const p = this.position;
        if (
          p.x >= wall.min.x - BALL_RADIUS &&
          p.x <= wall.max.x + BALL_RADIUS &&
          p.y >= wall.min.y - BALL_RADIUS &&
          p.y <= wall.max.y + BALL_RADIUS &&
          p.z >= wall.min.z - BALL_RADIUS &&
          p.z <= wall.max.z + BALL_RADIUS
        ) {
          this.position.add(wall.normal.clone().multiplyScalar(BALL_RADIUS - dist));
          const dot = this.velocity.dot(wall.normal);
          if (dot < 0) {
            this.velocity.sub(wall.normal.clone().multiplyScalar(2 * dot));
            this.velocity.multiplyScalar(WALL_BOUNCE);
            this.audio.playWallBounce(this.velocity.length());
          }
        }
      }
    }
  }

  private checkBumperCollisions() {
    const bumpers = (this.world as any).__holoGolfBumpers as BumperCollider[] | undefined;
    if (!bumpers) return;

    for (const bumper of bumpers) {
      const dx = this.position.x - bumper.position.x;
      const dz = this.position.z - bumper.position.z;
      const dist2D = Math.sqrt(dx * dx + dz * dz);
      const minDist = BALL_RADIUS + bumper.radius;

      if (dist2D < minDist && Math.abs(this.position.y - bumper.position.y) < 0.15) {
        // Push ball out
        if (dist2D > 0.001) {
          const nx = dx / dist2D;
          const nz = dz / dist2D;
          this.position.x = bumper.position.x + nx * minDist;
          this.position.z = bumper.position.z + nz * minDist;

          // Reflect and boost velocity
          const normal = new Vector3(nx, 0, nz);
          const dot = this.velocity.dot(normal);
          if (dot < 0) {
            this.velocity.sub(normal.multiplyScalar(2 * dot));
            this.velocity.multiplyScalar(BUMPER_BOUNCE);
            // Clamp after boost
            if (this.velocity.length() > MAX_VELOCITY) {
              this.velocity.normalize().multiplyScalar(MAX_VELOCITY);
            }
            this.audio.playBumperHit(this.velocity.length());
          }
        }
      }
    }
  }

  // === Trail system (object pool) ===

  private initTrailPool(count: number) {
    const geo = new SphereGeometry(BALL_RADIUS * 0.5, 4, 4);
    for (let i = 0; i < count; i++) {
      const mat = new MeshBasicMaterial({
        color: 0x00ffff,
        transparent: true,
        opacity: 0,
        blending: AdditiveBlending,
      });
      const dot = new Mesh(geo, mat);
      dot.visible = false;
      this.trailGroup.add(dot);
      this.trailPool.push(dot);
    }
  }

  private updateTrail() {
    if (this.stopped) {
      // Fade out existing trail
      for (let i = 0; i < this.trailActiveCount; i++) {
        const dot = this.trailPool[i];
        const mat = dot.material as MeshBasicMaterial;
        mat.opacity *= 0.9;
        if (mat.opacity < 0.01) {
          dot.visible = false;
        }
      }
      return;
    }

    const speed = this.velocity.length();
    if (speed < 0.1) return;

    // Add current position
    this.trailPositions.push(this.position.clone());
    if (this.trailPositions.length > this.trailPool.length) {
      this.trailPositions.shift();
    }

    // Update pool meshes
    this.trailActiveCount = this.trailPositions.length;
    for (let i = 0; i < this.trailPool.length; i++) {
      const dot = this.trailPool[i];
      if (i < this.trailPositions.length) {
        const t = i / this.trailPositions.length;
        dot.position.copy(this.trailPositions[i]);
        dot.scale.setScalar(t);
        const mat = dot.material as MeshBasicMaterial;
        mat.opacity = t * 0.4;
        mat.color.lerpColors(new Color(0x00ffff), new Color(0xff4488), t);
        dot.visible = true;
      } else {
        dot.visible = false;
      }
    }
  }

  private clearTrail() {
    this.trailPositions = [];
    this.trailActiveCount = 0;
    for (const dot of this.trailPool) {
      dot.visible = false;
    }
  }
}

/**
 * Holo Golf VR — Putter Controller
 * XR: Putter follows right controller, swing detects putt.
 * Browser: Click-and-drag power/direction mechanic.
 */
import {
  World,
  Vector3,
  Mesh,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Group,
  Color,
  BoxGeometry,
  SphereGeometry,
  LineSegments,
  EdgesGeometry,
  LineBasicMaterial,
  AdditiveBlending,
  BufferGeometry,
  Float32BufferAttribute,
  Line,
} from "@iwsdk/core";
import { BallController } from "./ball";
import { AudioManager } from "./audio";

const SHAFT_LENGTH = 0.9;
const HEAD_SIZE = 0.06;
const SWING_THRESHOLD = 0.8;
const MAX_POWER = 10.0;
const BROWSER_POWER_SCALE = 0.06;

export class PutterController {
  private world: World;
  private ball: BallController;
  private audio: AudioManager;
  private group: Group;
  private headMesh: Mesh;
  private shaftMesh: Mesh;
  private active = false;

  // XR swing tracking
  private prevControllerPos = new Vector3();
  private controllerVelocity = new Vector3();
  private isSwinging = false;
  private swingCooldown = 0;

  // Browser aiming
  aimDirection = new Vector3(0, 0, -1);
  aimPower = 0;
  isAiming = false;
  private aimLine: Line;
  private aimDots: Mesh[] = [];
  private aimGroup: Group;
  private dragStart = new Vector3();

  constructor(world: World, ball: BallController, audio: AudioManager) {
    this.world = world;
    this.ball = ball;
    this.audio = audio;

    this.group = new Group();

    // Shaft — thin glowing cylinder
    const shaftGeo = new CylinderGeometry(0.006, 0.008, SHAFT_LENGTH, 8);
    const shaftMat = new MeshStandardMaterial({
      color: new Color(0x8844ff),
      emissive: new Color(0x6622cc),
      emissiveIntensity: 0.8,
      metalness: 0.7,
      roughness: 0.2,
    });
    this.shaftMesh = new Mesh(shaftGeo, shaftMat);
    this.shaftMesh.position.y = SHAFT_LENGTH / 2;
    this.group.add(this.shaftMesh);

    // Head — flat rectangular head
    const headGeo = new BoxGeometry(HEAD_SIZE, 0.03, HEAD_SIZE * 1.8);
    const headMat = new MeshStandardMaterial({
      color: new Color(0xaa66ff),
      emissive: new Color(0x8844dd),
      emissiveIntensity: 1.0,
      metalness: 0.8,
      roughness: 0.1,
    });
    this.headMesh = new Mesh(headGeo, headMat);
    this.headMesh.position.y = 0;
    this.headMesh.position.z = HEAD_SIZE * 0.5;
    this.group.add(this.headMesh);

    // Wireframe edges on head
    const headEdges = new EdgesGeometry(headGeo);
    const edgeMat = new LineBasicMaterial({ color: 0xcc88ff, transparent: true, opacity: 0.8 });
    const wireHead = new LineSegments(headEdges, edgeMat);
    this.headMesh.add(wireHead);

    // Aim line (browser mode)
    const lineGeo = new BufferGeometry();
    const positions = new Float32Array(2 * 3);
    lineGeo.setAttribute("position", new Float32BufferAttribute(positions, 3));
    this.aimLine = new Line(
      lineGeo,
      new LineBasicMaterial({
        color: 0xff4488,
        transparent: true,
        opacity: 0.7,
      }),
    );
    this.aimLine.visible = false;

    this.aimGroup = new Group();
    world.scene.add(this.aimGroup);
    world.scene.add(this.aimLine);
    world.scene.add(this.group);
    this.group.visible = false;
  }

  setActive(active: boolean) {
    this.active = active;
    this.group.visible = active;
    if (!active) {
      this.hideAim();
    }
  }

  // === Browser aiming ===

  startAim(mouseX: number, mouseY: number) {
    if (!this.active || !this.ball.isActive) return;
    this.isAiming = true;
    this.dragStart.set(mouseX, 0, mouseY);
    this.aimPower = 0;
  }

  updateAim(mouseX: number, mouseY: number) {
    if (!this.isAiming) return;

    const dx = mouseX - this.dragStart.x;
    const dy = mouseY - this.dragStart.z;
    const dist = Math.sqrt(dx * dx + dy * dy);

    this.aimPower = Math.min(dist * BROWSER_POWER_SCALE, MAX_POWER);

    // Direction is opposite to drag (pull back = hit forward)
    if (dist > 1) {
      this.aimDirection.set(-dx / dist, 0, -dy / dist).normalize();
    }

    this.showAim();
  }

  releaseAim() {
    if (!this.isAiming) return;
    this.isAiming = false;

    if (this.aimPower > 0.1) {
      this.ball.hit(this.aimDirection.clone(), this.aimPower);
      this.audio.playSwing(this.aimPower / MAX_POWER);
    }

    this.hideAim();
    this.aimPower = 0;
  }

  private showAim() {
    if (!this.ball.isActive) return;

    const ballPos = this.ball.position.clone();
    ballPos.y = this.ball.position.y;

    // Direction line
    const lineEnd = ballPos.clone().add(this.aimDirection.clone().multiplyScalar(this.aimPower * 0.3));
    const posAttr = this.aimLine.geometry.getAttribute("position");
    (posAttr.array as Float32Array)[0] = ballPos.x;
    (posAttr.array as Float32Array)[1] = ballPos.y;
    (posAttr.array as Float32Array)[2] = ballPos.z;
    (posAttr.array as Float32Array)[3] = lineEnd.x;
    (posAttr.array as Float32Array)[4] = lineEnd.y;
    (posAttr.array as Float32Array)[5] = lineEnd.z;
    posAttr.needsUpdate = true;
    this.aimLine.visible = true;

    // Power dots
    this.aimDots.forEach((d) => this.aimGroup.remove(d));
    this.aimDots = [];

    const numDots = Math.ceil(this.aimPower * 2);
    for (let i = 0; i < numDots && i < 20; i++) {
      const t = (i + 1) / (numDots + 1);
      const dotPos = ballPos.clone().add(this.aimDirection.clone().multiplyScalar(t * this.aimPower * 0.3));
      const geo = new SphereGeometry(0.008, 6, 6);
      const mat = new MeshBasicMaterial({
        color: new Color().lerpColors(new Color(0x00ffff), new Color(0xff4488), t),
        transparent: true,
        opacity: 0.8 - t * 0.4,
        blending: AdditiveBlending,
      });
      const dot = new Mesh(geo, mat);
      dot.position.copy(dotPos);
      this.aimGroup.add(dot);
      this.aimDots.push(dot);
    }
  }

  private hideAim() {
    this.aimLine.visible = false;
    this.aimDots.forEach((d) => this.aimGroup.remove(d));
    this.aimDots = [];
  }

  // === XR Swing ===

  updateXR(controllerPos: Vector3, controllerQuat: any) {
    if (!this.active || this.swingCooldown > 0) return;

    // Track controller velocity
    this.controllerVelocity.copy(controllerPos).sub(this.prevControllerPos);
    this.prevControllerPos.copy(controllerPos);

    // Position putter at controller
    this.group.position.copy(controllerPos);
    this.group.position.y -= SHAFT_LENGTH;
    if (controllerQuat) {
      this.group.quaternion.copy(controllerQuat);
    }

    // Detect swing
    const speed = this.controllerVelocity.length() * 60; // per second
    if (speed > SWING_THRESHOLD) {
      // Check if putter head is near ball
      const headWorldPos = new Vector3();
      this.headMesh.getWorldPosition(headWorldPos);
      const dist = headWorldPos.distanceTo(this.ball.position);

      if (dist < 0.2) {
        const power = Math.min(speed * 3, MAX_POWER);
        const dir = this.controllerVelocity.clone().normalize();
        dir.y = 0;
        dir.normalize();
        this.ball.hit(dir, power);
        this.audio.playSwing(power / MAX_POWER);
        this.swingCooldown = 0.5;
      }
    }
  }

  update(dt: number, world: World) {
    if (this.swingCooldown > 0) {
      this.swingCooldown -= dt;
    }

    if (!this.active) return;

    // In browser mode, position putter near ball
    if (!this.isAiming) {
      const ballPos = this.ball.position;
      this.group.position.set(ballPos.x + 0.15, ballPos.y + SHAFT_LENGTH * 0.5, ballPos.z);
      this.group.rotation.set(0, 0, -0.15);
    }

    // Putter glow pulse
    const pulse = 0.8 + Math.sin(performance.now() * 0.003) * 0.2;
    (this.headMesh.material as MeshStandardMaterial).emissiveIntensity = pulse;
  }
}

/**
 * Holo Golf VR — XR Input Handler (Round 3 Overhaul)
 * Full end-to-end XR controller support across ALL game states:
 * - Title screen: trigger/A to navigate, thumbstick to browse
 * - Course select: trigger/A to select course, thumbstick L/R to browse, B for back
 * - Playing/Aiming: trigger to putt, grip for power boost, B to reset, thumbstick to orbit
 * - Hole Complete: auto-advance or A to skip
 * - Course Complete: trigger/A to replay/menu, thumbstick to select option
 * - Scorecard: B to toggle, thumbstick to scroll
 */
import { World, Vector3, Quaternion, Group, Mesh, CylinderGeometry, MeshBasicMaterial, Color, AdditiveBlending, Line, BufferGeometry, Float32BufferAttribute, LineBasicMaterial, SphereGeometry } from "@iwsdk/core";
import { InputComponent } from "@iwsdk/core";
import { PutterController } from "./putter";
import { GameManager, GameState } from "./game";
import { UIManager } from "./ui";

const THUMBSTICK_DEADZONE = 0.3;
const THUMBSTICK_COOLDOWN = 0.25; // seconds between menu nav ticks

export class XRInputHandler {
  private world: World;
  private putter: PutterController;
  private game: GameManager;
  private ui: UIManager;

  // Controller tracking
  private prevRightPos = new Vector3();
  private prevLeftPos = new Vector3();
  private rightVelocity = new Vector3();

  // Thumbstick menu navigation
  private thumbCooldownRight = 0;
  private thumbCooldownLeft = 0;

  // Menu cursor state
  private menuCursorIndex = 0; // which menu item is "focused"
  private lastMenuScreen = "";

  // Laser pointer visualization
  private laserLine: Line;
  private laserDot: Mesh;
  private laserGroup: Group;

  // Grip boost state
  private gripHeld = false;
  private gripBoostMultiplier = 1.0;

  // Camera orbit via left thumbstick
  cameraOrbitDelta = { horizontal: 0, vertical: 0 };

  constructor(
    world: World,
    putter: PutterController,
    game: GameManager,
    ui: UIManager,
  ) {
    this.world = world;
    this.putter = putter;
    this.game = game;
    this.ui = ui;

    // Build laser pointer
    this.laserGroup = new Group();
    const lineGeo = new BufferGeometry();
    const positions = new Float32Array(6);
    lineGeo.setAttribute("position", new Float32BufferAttribute(positions, 3));
    this.laserLine = new Line(
      lineGeo,
      new LineBasicMaterial({
        color: 0x00ffff,
        transparent: true,
        opacity: 0.6,
      }),
    );
    this.laserLine.visible = false;
    this.laserGroup.add(this.laserLine);

    // Laser endpoint dot
    const dotGeo = new SphereGeometry(0.008, 8, 8);
    const dotMat = new MeshBasicMaterial({
      color: 0x00ffff,
      transparent: true,
      opacity: 0.8,
      blending: AdditiveBlending,
    });
    this.laserDot = new Mesh(dotGeo, dotMat);
    this.laserDot.visible = false;
    this.laserGroup.add(this.laserDot);

    world.scene.add(this.laserGroup);

    // Reset cursor when game state changes
    game.onStateChange(() => {
      this.menuCursorIndex = 0;
    });
  }

  update(dt: number) {
    // Tick cooldowns
    if (this.thumbCooldownRight > 0) this.thumbCooldownRight -= dt;
    if (this.thumbCooldownLeft > 0) this.thumbCooldownLeft -= dt;

    // Reset camera orbit delta
    this.cameraOrbitDelta.horizontal = 0;
    this.cameraOrbitDelta.vertical = 0;

    // Access XR input — handle both 0.3.x and 0.4.x API shapes
    const input = this.world.input as any;
    const xr = input?.xr ?? input;
    if (!xr) return;

    const rightGamepad = xr.gamepads?.right;
    const leftGamepad = xr.gamepads?.left;

    if (!rightGamepad) return;

    // Get right controller position for putter tracking
    const playerSpaceEntities = (this.world as any).playerSpaceEntities;
    const rightGripSpace = playerSpaceEntities?.gripSpaces?.right;
    const rightRaySpace = playerSpaceEntities?.raySpaces?.right;

    if (rightGripSpace) {
      const pos = new Vector3();
      const quat = new Quaternion();
      rightGripSpace.object3D.getWorldPosition(pos);
      rightGripSpace.object3D.getWorldQuaternion(quat);

      // Track velocity for swing detection
      this.rightVelocity.copy(pos).sub(this.prevRightPos);
      this.prevRightPos.copy(pos);

      this.putter.updateXR(pos, quat);
    }

    // Update laser pointer (visible in menus and aiming)
    this.updateLaserPointer(rightRaySpace || rightGripSpace);

    // Route input by game state
    const state = this.game.state;

    if (this.ui.isVisible()) {
      this.handleMenuInput(rightGamepad, leftGamepad, dt);
    } else if (state === GameState.AIMING) {
      this.handleAimingInput(rightGamepad, leftGamepad, dt);
    } else if (state === GameState.BALL_MOVING) {
      this.handleBallMovingInput(leftGamepad, dt);
    } else if (state === GameState.HOLE_COMPLETE) {
      this.handleHoleCompleteInput(rightGamepad);
    } else if (state === GameState.COURSE_COMPLETE) {
      this.handleCourseCompleteInput(rightGamepad);
    }

    // Grip button tracking (works in any state)
    const gripHeld = rightGamepad.getButtonPressed?.(InputComponent.Squeeze);
    this.gripHeld = !!gripHeld;
    if (this.gripHeld) {
      this.gripBoostMultiplier = Math.min(this.gripBoostMultiplier + dt * 0.8, 1.5);
    } else {
      this.gripBoostMultiplier = Math.max(this.gripBoostMultiplier - dt * 2.0, 1.0);
    }
  }

  // Get the grip boost multiplier for power shots
  getGripBoost(): number {
    return this.gripBoostMultiplier;
  }

  private updateLaserPointer(gripSpace: any) {
    const showLaser = this.ui.isVisible() || this.game.state === GameState.AIMING;

    if (!gripSpace || !showLaser) {
      this.laserLine.visible = false;
      this.laserDot.visible = false;
      return;
    }

    const pos = new Vector3();
    const dir = new Vector3(0, 0, -1);
    gripSpace.object3D.getWorldPosition(pos);
    gripSpace.object3D.getWorldQuaternion(new Quaternion());

    // In aiming mode, point toward the ball
    if (this.game.state === GameState.AIMING && this.putter.isAiming) {
      // Laser shows aim direction
      const ballPos = (this.game as any).ball?.position;
      if (ballPos) {
        dir.copy(this.putter.aimDirection);
      }
    }

    const end = pos.clone().add(dir.multiplyScalar(3));
    const posAttr = this.laserLine.geometry.getAttribute("position");
    const arr = posAttr.array as Float32Array;
    arr[0] = pos.x; arr[1] = pos.y; arr[2] = pos.z;
    arr[3] = end.x; arr[4] = end.y; arr[5] = end.z;
    posAttr.needsUpdate = true;

    this.laserLine.visible = true;
    this.laserDot.position.copy(end);
    this.laserDot.visible = true;
  }

  // === Menu navigation with controllers ===

  private handleMenuInput(rightGamepad: any, leftGamepad: any, dt: number) {
    // Trigger or A to select current menu item
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);

    if (triggerDown || aDown) {
      this.ui.handleSelect();
    }

    // B button to go back
    const bDown = rightGamepad.getButtonDown?.(InputComponent.B_Button);
    if (bDown) {
      this.ui.handleBack();
    }

    // Thumbstick for menu navigation
    const rightThumb = rightGamepad.getAxesValues?.(InputComponent.Thumbstick);
    if (rightThumb && this.thumbCooldownRight <= 0) {
      if (rightThumb.x > THUMBSTICK_DEADZONE || rightThumb.y > THUMBSTICK_DEADZONE) {
        this.ui.handleNavNext();
        this.thumbCooldownRight = THUMBSTICK_COOLDOWN;
      } else if (rightThumb.x < -THUMBSTICK_DEADZONE || rightThumb.y < -THUMBSTICK_DEADZONE) {
        this.ui.handleNavPrev();
        this.thumbCooldownRight = THUMBSTICK_COOLDOWN;
      }
    }

    // Left thumbstick also works for navigation
    if (leftGamepad) {
      const leftThumb = leftGamepad.getAxesValues?.(InputComponent.Thumbstick);
      if (leftThumb && this.thumbCooldownLeft <= 0) {
        if (leftThumb.x > THUMBSTICK_DEADZONE) {
          this.ui.handleNavNext();
          this.thumbCooldownLeft = THUMBSTICK_COOLDOWN;
        } else if (leftThumb.x < -THUMBSTICK_DEADZONE) {
          this.ui.handleNavPrev();
          this.thumbCooldownLeft = THUMBSTICK_COOLDOWN;
        }
      }
    }
  }

  // === Aiming state (controller-based putting) ===

  private handleAimingInput(rightGamepad: any, leftGamepad: any, dt: number) {
    // Trigger fires the putt (swing detection also works via putter.updateXR)
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);
    if (triggerDown && this.putter.isAiming) {
      // Quick-fire with current aim direction if set
      this.putter.releaseAim();
      this.game.onStroke();
    }

    // B button resets ball to tee
    const bDown = rightGamepad.getButtonDown?.(InputComponent.B_Button);
    if (bDown) {
      this.game.resetBall();
    }

    // A button toggles scorecard
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);
    if (aDown) {
      // Could toggle scorecard - for now, handle via browser input
    }

    // Left thumbstick orbits camera around ball
    if (leftGamepad) {
      const leftThumb = leftGamepad.getAxesValues?.(InputComponent.Thumbstick);
      if (leftThumb) {
        if (Math.abs(leftThumb.x) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.horizontal = leftThumb.x * dt * 2.0;
        }
        if (Math.abs(leftThumb.y) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.vertical = -leftThumb.y * dt * 1.5;
        }
      }
    }
  }

  // === Ball moving (just camera orbit) ===

  private handleBallMovingInput(leftGamepad: any, dt: number) {
    if (leftGamepad) {
      const leftThumb = leftGamepad.getAxesValues?.(InputComponent.Thumbstick);
      if (leftThumb) {
        if (Math.abs(leftThumb.x) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.horizontal = leftThumb.x * dt * 2.0;
        }
        if (Math.abs(leftThumb.y) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.vertical = -leftThumb.y * dt * 1.5;
        }
      }
    }
  }

  // === Hole complete ===

  private handleHoleCompleteInput(rightGamepad: any) {
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);

    if (aDown || triggerDown) {
      // Skip the auto-timer and go to next hole immediately
      this.game.skipToNextHole();
    }
  }

  // === Course complete ===

  private handleCourseCompleteInput(rightGamepad: any) {
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);

    if (aDown || triggerDown) {
      this.ui.showCourseComplete();
    }
  }
}

/**
 * Holo Golf VR — Course Manager
 * Defines hole layouts and builds geometry. Each hole is a neon wireframe platform.
 * Now supports bumper collision, teleporters, wind zones, and ice surfaces.
 */
import {
  World,
  Vector3,
  Group,
  Mesh,
  BoxGeometry,
  PlaneGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  Color,
  DoubleSide,
  AdditiveBlending,
  RingGeometry,
  TorusGeometry,
  SphereGeometry,
  PointLight,
  Float32BufferAttribute,
  BufferGeometry,
  Line,
} from "@iwsdk/core";
import { QUANTUM_FIELD_COURSE } from "./course2";
import { COSMIC_ABYSS_COURSE } from "./course3";
import type { BumperCollider } from "./ball";
import {
  createTeleportPad,
  createWindZone,
  createIceSurface,
  TeleportPad,
  WindZone,
  IceSurface,
} from "./specialobstacles";

export interface WallDef {
  normal: Vector3;
  point: Vector3;
  min: Vector3;
  max: Vector3;
}

export interface HoleData {
  index: number;
  name: string;
  par: number;
  teePosition: Vector3;
  holePosition: Vector3;
  surfaces: SurfaceDef[];
  walls: WallSegment[];
  obstacles: ObstacleDef[];
  decorations: DecorationDef[];
  specialObstacles?: SpecialObstacleDef[];
}

export interface SurfaceDef {
  position: Vector3;
  size: [number, number, number]; // width, height(thickness), depth
  color?: number;
  slope?: { axis: "x" | "z"; angle: number };
}

export interface WallSegment {
  position: Vector3;
  size: [number, number, number];
  color?: number;
}

export interface ObstacleDef {
  type: "windmill" | "bumper" | "spinner" | "moving_wall" | "ramp";
  position: Vector3;
  params: Record<string, any>;
}

export interface SpecialObstacleDef {
  type: "teleporter" | "wind_zone" | "ice_surface";
  position: Vector3;
  params: Record<string, any>;
}

export interface DecorationDef {
  type: "pillar" | "ring" | "orb" | "arrow";
  position: Vector3;
  params?: Record<string, any>;
}

export interface CourseData {
  name: string;
  description: string;
  holes: HoleData[];
  themeColor: number;
}

export class CourseManager {
  private world: World;
  private holeGroup: Group;
  private obstacleAnims: Array<{ mesh: any; update: (dt: number) => void }> = [];

  // Special obstacle state
  teleporters: TeleportPad[] = [];
  windZones: WindZone[] = [];
  iceSurfaces: IceSurface[] = [];

  constructor(world: World) {
    this.world = world;
    this.holeGroup = new Group();
    world.scene.add(this.holeGroup);
  }

  getCourse(index: number): CourseData {
    return COURSES[Math.min(index, COURSES.length - 1)];
  }

  getCourseCount(): number {
    return COURSES.length;
  }

  clearCurrentHole() {
    while (this.holeGroup.children.length > 0) {
      this.holeGroup.remove(this.holeGroup.children[0]);
    }
    this.obstacleAnims = [];
    (this.world as any).__holoGolfWalls = [];
    (this.world as any).__holoGolfBumpers = [];
    this.teleporters = [];
    this.windZones = [];
    this.iceSurfaces = [];
  }

  buildHole(hole: HoleData) {
    const walls: WallDef[] = [];
    const bumpers: BumperCollider[] = [];

    // Build surfaces (floor panels)
    for (const surf of hole.surfaces) {
      const panel = this.createPanel(surf);
      this.holeGroup.add(panel);
    }

    // Build walls
    for (const wallSeg of hole.walls) {
      const { mesh, wallDef } = this.createWall(wallSeg);
      this.holeGroup.add(mesh);
      walls.push(wallDef);
    }

    // Build obstacles
    for (const obs of hole.obstacles) {
      const { mesh, update, bumperCollider } = this.createObstacle(obs);
      this.holeGroup.add(mesh);
      if (update) {
        this.obstacleAnims.push({ mesh, update });
      }
      if (bumperCollider) {
        bumpers.push(bumperCollider);
      }
    }

    // Build special obstacles
    if (hole.specialObstacles) {
      for (const special of hole.specialObstacles) {
        this.buildSpecialObstacle(special);
      }
    }

    // Build decorations
    for (const dec of hole.decorations) {
      const mesh = this.createDecoration(dec);
      this.holeGroup.add(mesh);
    }

    // Tee marker
    this.holeGroup.add(this.createTeeMarker(hole.teePosition));

    // Hole cup
    this.holeGroup.add(this.createHoleCup(hole.holePosition));

    // Register colliders
    (this.world as any).__holoGolfWalls = walls;
    (this.world as any).__holoGolfBumpers = bumpers;
  }

  private buildSpecialObstacle(special: SpecialObstacleDef) {
    switch (special.type) {
      case "teleporter": {
        const target = special.params.target as Vector3;
        const pad = createTeleportPad(special.position, target, special.params.color);
        this.holeGroup.add(pad.group);
        this.teleporters.push(pad);
        break;
      }
      case "wind_zone": {
        const dir = special.params.direction as Vector3;
        const force = special.params.force || 2;
        const size = special.params.size as Vector3 || new Vector3(1, 0.5, 1);
        const zone = createWindZone(special.position, dir, force, size);
        this.holeGroup.add(zone.group);
        this.windZones.push(zone);
        break;
      }
      case "ice_surface": {
        const size = special.params.size as Vector3 || new Vector3(1, 0.01, 1);
        const ice = createIceSurface(special.position, size);
        this.holeGroup.add(ice.group);
        this.iceSurfaces.push(ice);
        break;
      }
    }
  }

  updateObstacles(dt: number) {
    for (const anim of this.obstacleAnims) {
      anim.update(dt);
    }

    // Animate teleporter pads
    for (const tp of this.teleporters) {
      if (tp.cooldown > 0) {
        tp.cooldown -= dt;
        if (tp.cooldown <= 0) tp.active = true;
      }
      // Rotate orbiting particles
      const children = tp.group.children;
      for (let i = 2; i < 6 && i < children.length; i++) {
        const child = children[i];
        const angle = performance.now() * 0.002 + (i - 2) * Math.PI * 0.5;
        child.position.x = Math.cos(angle) * 0.1;
        child.position.z = Math.sin(angle) * 0.1;
      }
    }
  }

  // Check special zone interactions with ball
  checkBallZones(ballPos: Vector3, ballVelocity: Vector3): {
    teleported: boolean;
    teleportTarget?: Vector3;
    windForce: Vector3;
    frictionOverride: number | null;
  } {
    let teleported = false;
    let teleportTarget: Vector3 | undefined;
    const windForce = new Vector3();
    let frictionOverride: number | null = null;

    // Check teleporters
    for (const tp of this.teleporters) {
      if (!tp.active) continue;
      const dist = ballPos.distanceTo(tp.position);
      if (dist < tp.radius) {
        teleported = true;
        teleportTarget = tp.targetPosition.clone();
        tp.active = false;
        tp.cooldown = 1.5;
        break;
      }
    }

    // Check wind zones
    for (const wz of this.windZones) {
      const dx = Math.abs(ballPos.x - wz.position.x);
      const dz = Math.abs(ballPos.z - wz.position.z);
      if (dx < wz.size.x / 2 && dz < wz.size.z / 2) {
        windForce.add(wz.direction.clone().multiplyScalar(wz.force));
      }
    }

    // Check ice surfaces
    for (const ice of this.iceSurfaces) {
      const dx = Math.abs(ballPos.x - ice.position.x);
      const dz = Math.abs(ballPos.z - ice.position.z);
      if (dx < ice.size.x / 2 && dz < ice.size.z / 2) {
        frictionOverride = ice.friction;
      }
    }

    return { teleported, teleportTarget, windForce, frictionOverride };
  }

  private createPanel(surf: SurfaceDef): Group {
    const group = new Group();
    const [w, h, d] = surf.size;
    const color = surf.color || 0x004466;

    const geo = new BoxGeometry(w, h, d);
    const mat = new MeshStandardMaterial({
      color: new Color(color),
      emissive: new Color(color).multiplyScalar(0.3),
      emissiveIntensity: 0.5,
      metalness: 0.6,
      roughness: 0.3,
      transparent: true,
      opacity: 0.85,
    });
    const mesh = new Mesh(geo, mat);

    const edges = new EdgesGeometry(geo);
    const edgeMat = new LineBasicMaterial({
      color: new Color(color).multiplyScalar(2),
      transparent: true,
      opacity: 0.9,
    });
    const wire = new LineSegments(edges, edgeMat);
    mesh.add(wire);

    mesh.position.copy(surf.position);

    if (surf.slope) {
      if (surf.slope.axis === "x") {
        mesh.rotation.z = surf.slope.angle;
      } else {
        mesh.rotation.x = surf.slope.angle;
      }
    }

    group.add(mesh);
    return group;
  }

  private createWall(wallSeg: WallSegment): { mesh: Group; wallDef: WallDef } {
    const group = new Group();
    const [w, h, d] = wallSeg.size;
    const color = wallSeg.color || 0x0088aa;

    const geo = new BoxGeometry(w, h, d);
    const mat = new MeshStandardMaterial({
      color: new Color(color),
      emissive: new Color(color).multiplyScalar(0.4),
      emissiveIntensity: 0.6,
      metalness: 0.5,
      roughness: 0.4,
      transparent: true,
      opacity: 0.6,
    });
    const mesh = new Mesh(geo, mat);

    const edges = new EdgesGeometry(geo);
    const edgeMat = new LineBasicMaterial({ color: 0x00ddff, transparent: true, opacity: 0.9 });
    mesh.add(new LineSegments(edges, edgeMat));

    mesh.position.copy(wallSeg.position);
    group.add(mesh);

    let normal: Vector3;
    if (w < d) {
      normal = new Vector3(1, 0, 0);
    } else {
      normal = new Vector3(0, 0, 1);
    }

    const wallDef: WallDef = {
      normal,
      point: wallSeg.position.clone(),
      min: new Vector3(
        wallSeg.position.x - w / 2,
        wallSeg.position.y - h / 2,
        wallSeg.position.z - d / 2,
      ),
      max: new Vector3(
        wallSeg.position.x + w / 2,
        wallSeg.position.y + h / 2,
        wallSeg.position.z + d / 2,
      ),
    };

    return { mesh: group, wallDef };
  }

  private createObstacle(obs: ObstacleDef): {
    mesh: Group;
    update?: (dt: number) => void;
    bumperCollider?: BumperCollider;
  } {
    const group = new Group();
    group.position.copy(obs.position);

    switch (obs.type) {
      case "windmill": {
        const armGeo = new BoxGeometry(obs.params.length || 1.0, 0.04, 0.06);
        const armMat = new MeshStandardMaterial({
          color: 0xff4488,
          emissive: new Color(0xff2266),
          emissiveIntensity: 0.8,
        });
        const arm = new Mesh(armGeo, armMat);
        arm.position.y = 0.08;
        const armEdges = new LineSegments(
          new EdgesGeometry(armGeo),
          new LineBasicMaterial({ color: 0xff88aa }),
        );
        arm.add(armEdges);

        const postGeo = new CylinderGeometry(0.03, 0.03, 0.2, 8);
        const postMat = new MeshStandardMaterial({
          color: 0xff4488,
          emissive: new Color(0xff2266),
          emissiveIntensity: 0.6,
        });
        const post = new Mesh(postGeo, postMat);
        post.position.y = 0.1;

        group.add(post);
        group.add(arm);

        const speed = obs.params.speed || 1.5;
        let angle = 0;
        return {
          mesh: group,
          update: (dt: number) => {
            angle += speed * dt;
            arm.rotation.y = angle;
          },
        };
      }

      case "bumper": {
        const radius = obs.params.radius || 0.1;
        const bGeo = new CylinderGeometry(radius, radius, 0.12, 16);
        const bMat = new MeshStandardMaterial({
          color: 0xffaa00,
          emissive: new Color(0xff8800),
          emissiveIntensity: 1.0,
        });
        const bumper = new Mesh(bGeo, bMat);
        bumper.position.y = 0.06;
        const bEdges = new LineSegments(
          new EdgesGeometry(bGeo),
          new LineBasicMaterial({ color: 0xffcc44 }),
        );
        bumper.add(bEdges);
        group.add(bumper);

        const pulseSpeed = 3;
        return {
          mesh: group,
          update: (dt: number) => {
            const s = 1 + Math.sin(performance.now() * 0.005 * pulseSpeed) * 0.08;
            bumper.scale.set(s, 1, s);
          },
          bumperCollider: {
            position: obs.position.clone(),
            radius,
            mesh: bumper,
          },
        };
      }

      case "spinner": {
        const ringGeo = new TorusGeometry(obs.params.radius || 0.3, 0.02, 8, 24);
        const ringMat = new MeshStandardMaterial({
          color: 0x44ff88,
          emissive: new Color(0x22cc66),
          emissiveIntensity: 0.8,
        });
        const ring = new Mesh(ringGeo, ringMat);
        ring.position.y = 0.1;
        ring.rotation.x = Math.PI / 2;
        group.add(ring);

        const speed = obs.params.speed || 2;
        return {
          mesh: group,
          update: (dt: number) => {
            ring.rotation.z += speed * dt;
          },
        };
      }

      case "moving_wall": {
        const mwGeo = new BoxGeometry(
          obs.params.width || 0.3,
          obs.params.height || 0.15,
          0.04,
        );
        const mwMat = new MeshStandardMaterial({
          color: 0xff6644,
          emissive: new Color(0xcc4422),
          emissiveIntensity: 0.7,
        });
        const mw = new Mesh(mwGeo, mwMat);
        const mwEdges = new LineSegments(
          new EdgesGeometry(mwGeo),
          new LineBasicMaterial({ color: 0xff8866 }),
        );
        mw.add(mwEdges);
        group.add(mw);

        const range = obs.params.range || 0.5;
        const speed = obs.params.speed || 1.0;
        const axis = obs.params.axis || "x";
        let t = 0;
        return {
          mesh: group,
          update: (dt: number) => {
            t += speed * dt;
            if (axis === "x") {
              mw.position.x = Math.sin(t) * range;
            } else {
              mw.position.z = Math.sin(t) * range;
            }
          },
        };
      }

      case "ramp": {
        const rGeo = new BoxGeometry(obs.params.width || 0.4, 0.02, obs.params.depth || 0.3);
        const rMat = new MeshStandardMaterial({
          color: 0x4488ff,
          emissive: new Color(0x2266dd),
          emissiveIntensity: 0.6,
        });
        const ramp = new Mesh(rGeo, rMat);
        ramp.rotation.x = -(obs.params.angle || 0.2);
        const rEdges = new LineSegments(
          new EdgesGeometry(rGeo),
          new LineBasicMaterial({ color: 0x66aaff }),
        );
        ramp.add(rEdges);
        group.add(ramp);
        return { mesh: group };
      }
    }

    return { mesh: group };
  }

  private createDecoration(dec: DecorationDef): Group {
    const group = new Group();
    group.position.copy(dec.position);

    switch (dec.type) {
      case "pillar": {
        const h = dec.params?.height || 1.0;
        const pGeo = new CylinderGeometry(0.03, 0.03, h, 6);
        const pMat = new MeshStandardMaterial({
          color: 0x004466,
          emissive: new Color(0x003355),
          emissiveIntensity: 0.5,
          transparent: true,
          opacity: 0.7,
        });
        const pillar = new Mesh(pGeo, pMat);
        pillar.position.y = h / 2;
        const pEdges = new LineSegments(
          new EdgesGeometry(pGeo),
          new LineBasicMaterial({ color: 0x0088cc, transparent: true, opacity: 0.8 }),
        );
        pillar.add(pEdges);
        group.add(pillar);

        const orbGeo = new SphereGeometry(0.04, 8, 8);
        const orbMat = new MeshBasicMaterial({
          color: 0x00ffff,
          transparent: true,
          opacity: 0.6,
          blending: AdditiveBlending,
        });
        const orb = new Mesh(orbGeo, orbMat);
        orb.position.y = h + 0.04;
        group.add(orb);
        break;
      }

      case "ring": {
        const r = dec.params?.radius || 0.3;
        const rGeo = new TorusGeometry(r, 0.01, 6, 24);
        const rMat = new MeshBasicMaterial({
          color: dec.params?.color || 0x00ffff,
          transparent: true,
          opacity: 0.4,
          blending: AdditiveBlending,
        });
        const ring = new Mesh(rGeo, rMat);
        ring.rotation.x = Math.PI / 2;
        group.add(ring);
        break;
      }

      case "orb": {
        const oGeo = new SphereGeometry(dec.params?.radius || 0.06, 12, 12);
        const oMat = new MeshBasicMaterial({
          color: dec.params?.color || 0x00ffff,
          transparent: true,
          opacity: 0.5,
          blending: AdditiveBlending,
        });
        group.add(new Mesh(oGeo, oMat));
        break;
      }

      case "arrow": {
        const arrowGeo = new BufferGeometry();
        const verts = new Float32Array([
          0, 0.01, -0.1, -0.04, 0.01, 0.05, 0.04, 0.01, 0.05,
        ]);
        arrowGeo.setAttribute("position", new Float32BufferAttribute(verts, 3));
        const arrowMat = new MeshBasicMaterial({
          color: 0x00ff88,
          transparent: true,
          opacity: 0.6,
          side: DoubleSide,
          blending: AdditiveBlending,
        });
        const arrow = new Mesh(arrowGeo, arrowMat);
        if (dec.params?.rotation) {
          arrow.rotation.y = dec.params.rotation;
        }
        group.add(arrow);
        break;
      }
    }

    return group;
  }

  private createTeeMarker(pos: Vector3): Group {
    const group = new Group();
    group.position.copy(pos);

    const padGeo = new CylinderGeometry(0.08, 0.08, 0.005, 16);
    const padMat = new MeshBasicMaterial({
      color: 0x00ff88,
      transparent: true,
      opacity: 0.6,
      blending: AdditiveBlending,
    });
    const pad = new Mesh(padGeo, padMat);
    group.add(pad);

    const ringGeo = new RingGeometry(0.07, 0.09, 24);
    const ringMat = new MeshBasicMaterial({
      color: 0x00ff88,
      transparent: true,
      opacity: 0.5,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    const ring = new Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = 0.005;
    group.add(ring);

    return group;
  }

  private createHoleCup(pos: Vector3): Group {
    const group = new Group();
    group.position.copy(pos);

    const cupGeo = new CylinderGeometry(0.06, 0.06, 0.08, 16);
    const cupMat = new MeshStandardMaterial({
      color: 0x001122,
      emissive: new Color(0x000811),
      emissiveIntensity: 0.3,
    });
    const cup = new Mesh(cupGeo, cupMat);
    cup.position.y = -0.04;
    group.add(cup);

    const rimGeo = new TorusGeometry(0.06, 0.008, 8, 24);
    const rimMat = new MeshBasicMaterial({
      color: 0xffff00,
      transparent: true,
      opacity: 0.8,
      blending: AdditiveBlending,
    });
    const rim = new Mesh(rimGeo, rimMat);
    rim.rotation.x = Math.PI / 2;
    group.add(rim);

    const beaconGeo = new CylinderGeometry(0.002, 0.002, 0.8, 4);
    const beaconMat = new MeshBasicMaterial({
      color: 0xffff00,
      transparent: true,
      opacity: 0.3,
      blending: AdditiveBlending,
    });
    const beacon = new Mesh(beaconGeo, beaconMat);
    beacon.position.y = 0.4;
    group.add(beacon);

    const light = new PointLight(0xffff00, 0.5, 2);
    light.position.y = 0.1;
    group.add(light);

    const poleGeo = new CylinderGeometry(0.004, 0.004, 0.5, 6);
    const poleMat = new MeshStandardMaterial({
      color: 0xffffff,
      emissive: new Color(0x888888),
      emissiveIntensity: 0.5,
    });
    const pole = new Mesh(poleGeo, poleMat);
    pole.position.y = 0.25;
    pole.position.x = 0.04;
    group.add(pole);

    const flagGeo = new PlaneGeometry(0.08, 0.05);
    const flagMat = new MeshBasicMaterial({
      color: 0xff4488,
      transparent: true,
      opacity: 0.8,
      side: DoubleSide,
    });
    const flag = new Mesh(flagGeo, flagMat);
    flag.position.set(0.08, 0.48, 0);
    group.add(flag);

    return group;
  }
}

// ============================================================
// COURSE DEFINITIONS
// ============================================================

const COURSES: CourseData[] = [
  {
    name: "Neon Circuit",
    description: "9 holes of holographic mini golf through a neon data-stream",
    themeColor: 0x00ffff,
    holes: [
      {
        index: 0,
        name: "Straight Line",
