/**
 * Holo Golf VR — Scorecard (Round 3 Overhaul)
 * Detailed scorecard display as HTML overlay accessible mid-round.
 * Dynamically reads hole names from the active course.
 * Course-themed styling.
 */
import { GameManager, MAX_STROKES_PER_HOLE } from "./game";
import { CourseManager } from "./course";

const THEME_COLORS = [
  { primary: "#00ffff", secondary: "#003344" },
  { primary: "#ff44aa", secondary: "#330022" },
  { primary: "#ff6600", secondary: "#331100" },
];

export class ScorecardOverlay {
  private overlay: HTMLDivElement;
  private game: GameManager;
  private visible = false;

  constructor(game: GameManager) {
    this.game = game;
    this.overlay = document.createElement("div");
    this.overlay.id = "scorecard-overlay";
    this.overlay.style.cssText = `
      position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%);
      width: 500px; max-width: 92vw; padding: 25px;
      background: rgba(0, 10, 25, 0.95);
      border: 2px solid #00ccff;
      font-family: 'Courier New', monospace;
      color: #ffffff;
      z-index: 200;
      display: none;
      pointer-events: auto;
    `;
    document.body.appendChild(this.overlay);
  }

  toggle() {
    this.visible = !this.visible;
    if (this.visible) {
      this.redraw();
      this.overlay.style.display = "block";
    } else {
      this.overlay.style.display = "none";
    }
  }

  hide() {
    this.visible = false;
    this.overlay.style.display = "none";
  }

  isVisible(): boolean {
    return this.visible;
  }

  private redraw() {
    const score = this.game.courseScore;
    const totalPar = score.holes.reduce((s, h) => s + h.par, 0);
    const holeCount = score.holes.length;
    const theme = THEME_COLORS[this.game.currentCourseIndex] || THEME_COLORS[0];

    // Update border color to match course theme
    this.overlay.style.borderColor = theme.primary;

    // Get hole names from the course data
    const courseManager = this.game.courseManager;
    const courseData = courseManager?.getCourse(this.game.currentCourseIndex);

    let html = `
      <div style="text-align: center; margin-bottom: 15px;">
        <div style="font-size: 20px; color: ${theme.primary}; letter-spacing: 3px;">SCORECARD</div>
        <div style="font-size: 13px; color: #4488aa;">${score.courseName}</div>
        <div style="font-size: 10px; color: #334455; margin-top: 4px;">MAX ${MAX_STROKES_PER_HOLE} STROKES PER HOLE</div>
      </div>
      <table style="width: 100%; border-collapse: collapse; font-size: 13px;">
        <tr style="color: #4488aa; border-bottom: 1px solid ${theme.secondary};">
          <th style="padding: 4px 8px; text-align: left;">HOLE</th>
          <th style="padding: 4px 8px;">NAME</th>
          <th style="padding: 4px 8px;">PAR</th>
          <th style="padding: 4px 8px;">SCORE</th>
          <th style="padding: 4px 8px;">+/-</th>
        </tr>
    `;

    for (let i = 0; i < holeCount; i++) {
      const h = score.holes[i];
      const isCurrent = i === this.game.currentHoleIndex;
      const strokes = h.strokes > 0 ? h.strokes :
        (isCurrent ? this.game.currentStrokes : 0);
      const diff = strokes > 0 ? strokes - h.par : 0;

      const holeName = courseData?.holes[i]?.name ?? `Hole ${i + 1}`;
      const bgColor = isCurrent ? `${theme.secondary}40` : "transparent";
      const diffColor = diff < 0 ? "#00ff88" : diff === 0 ? "#ffffff" : "#ff6644";
      const diffText = strokes === 0 ? "-" :
        strokes === 1 ? "ACE" :
        strokes >= MAX_STROKES_PER_HOLE ? "MAX" :
        diff === 0 ? "E" :
        diff > 0 ? `+${diff}` : `${diff}`;

      html += `
        <tr style="background: ${bgColor}; border-bottom: 1px solid #112233;">
          <td style="padding: 4px 8px; color: ${isCurrent ? theme.primary : '#888'};">${i + 1}</td>
          <td style="padding: 4px 8px; color: #6688aa; font-size: 11px;">${holeName}</td>
          <td style="padding: 4px 8px; text-align: center;">${h.par}</td>
          <td style="padding: 4px 8px; text-align: center; font-weight: bold;">
            ${strokes > 0 ? strokes : '-'}
          </td>
          <td style="padding: 4px 8px; text-align: center; color: ${diffColor}; font-weight: bold;">
            ${diffText}
          </td>
        </tr>
      `;
    }

    const completedStrokes = score.holes.filter(h => h.strokes > 0).reduce((s, h) => s + h.strokes, 0);
    const completedPar = score.holes.filter(h => h.strokes > 0).reduce((s, h) => s + h.par, 0);

    html += `
        <tr style="border-top: 2px solid ${theme.primary}; color: ${theme.primary}; font-weight: bold;">
          <td colspan="2" style="padding: 6px 8px;">TOTAL</td>
          <td style="padding: 6px 8px; text-align: center;">${totalPar}</td>
          <td style="padding: 6px 8px; text-align: center;">${completedStrokes || '-'}</td>
          <td style="padding: 6px 8px; text-align: center;">
            ${completedStrokes > 0 ? (completedStrokes - completedPar <= 0 ? completedStrokes - completedPar : '+' + (completedStrokes - completedPar)) : '-'}
          </td>
        </tr>
      </table>
      <div style="text-align: center; margin-top: 12px; color: #334455; font-size: 11px;">
        Press TAB or click to close · VR: B button
      </div>
    `;

    this.overlay.innerHTML = html;
    this.overlay.addEventListener("click", () => this.hide());
  }
}

/**
 * Holo Golf VR — Mini Map
 * Overhead 2D mini-map showing hole layout, ball position, tee, and hole.
 * Rendered as an HTML overlay in the bottom-left corner.
 */
import { GameManager, GameState } from "./game";
import { BallController } from "./ball";
import { CourseManager, HoleData } from "./course";

export class MiniMap {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private game: GameManager;
  private ball: BallController;
  private visible = false;
  private animationFrame = 0;

  constructor(game: GameManager, ball: BallController) {
    this.game = game;
    this.ball = ball;

    this.canvas = document.createElement("canvas");
    this.canvas.width = 160;
    this.canvas.height = 160;
    this.canvas.style.cssText = `
      position: fixed; bottom: 20px; left: 20px;
      width: 140px; height: 140px;
      background: rgba(0, 10, 25, 0.8);
      border: 1px solid #003355;
      z-index: 110;
      display: none;
      image-rendering: pixelated;
    `;
    document.body.appendChild(this.canvas);
    this.ctx = this.canvas.getContext("2d")!;
  }

  update(dt: number) {
    const state = this.game.state;
    const shouldShow = state === GameState.AIMING || state === GameState.BALL_MOVING ||
                       state === GameState.HOLE_COMPLETE || state === GameState.PLAYING;

    if (shouldShow && !this.visible) {
      this.visible = true;
      this.canvas.style.display = "block";
    } else if (!shouldShow && this.visible) {
      this.visible = false;
      this.canvas.style.display = "none";
    }

    if (!this.visible) return;

    this.animationFrame++;
    if (this.animationFrame % 3 !== 0) return; // Render every 3rd frame for perf

    this.redraw();
  }

  private redraw() {
    const ctx = this.ctx;
    const w = this.canvas.width;
    const h = this.canvas.height;
    const hole = this.game.getCurrentHole();
    if (!hole) return;

    ctx.clearRect(0, 0, w, h);

    // Background with scan-line effect
    ctx.fillStyle = "rgba(0, 8, 18, 0.9)";
    ctx.fillRect(0, 0, w, h);

    // Border
    const colors = ["#00ccff", "#ff44aa", "#ff6600"];
    const themeColor = colors[this.game.currentCourseIndex] || colors[0];
    ctx.strokeStyle = themeColor;
    ctx.lineWidth = 1;
    ctx.strokeRect(1, 1, w - 2, h - 2);

    // Calculate bounds from hole geometry
    const tee = hole.teePosition;
    const cup = hole.holePosition;

    // Find extent of all surfaces
    let minX = Math.min(tee.x, cup.x);
    let maxX = Math.max(tee.x, cup.x);
    let minZ = Math.min(tee.z, cup.z);
    let maxZ = Math.max(tee.z, cup.z);

    for (const s of hole.surfaces) {
      const sx = s.position.x;
      const sz = s.position.z;
      const hw = s.size[0] / 2;
      const hd = s.size[2] / 2;
      minX = Math.min(minX, sx - hw);
      maxX = Math.max(maxX, sx + hw);
      minZ = Math.min(minZ, sz - hd);
      maxZ = Math.max(maxZ, sz + hd);
    }

    // Add padding
    const padX = (maxX - minX) * 0.15 + 0.5;
    const padZ = (maxZ - minZ) * 0.15 + 0.5;
    minX -= padX; maxX += padX;
    minZ -= padZ; maxZ += padZ;

    const rangeX = maxX - minX || 1;
    const rangeZ = maxZ - minZ || 1;
    const margin = 12;
    const drawW = w - margin * 2;
    const drawH = h - margin * 2;
    const scale = Math.min(drawW / rangeX, drawH / rangeZ);

    const toScreenX = (x: number) => margin + (x - minX) * scale;
    const toScreenZ = (z: number) => margin + (z - minZ) * scale;

    // Draw surfaces
    ctx.fillStyle = "rgba(0, 40, 60, 0.6)";
    ctx.strokeStyle = "rgba(0, 100, 140, 0.5)";
    ctx.lineWidth = 0.5;
    for (const s of hole.surfaces) {
      const sx = toScreenX(s.position.x - s.size[0] / 2);
      const sz = toScreenZ(s.position.z - s.size[2] / 2);
      const sw = s.size[0] * scale;
      const sh = s.size[2] * scale;
      ctx.fillRect(sx, sz, sw, sh);
      ctx.strokeRect(sx, sz, sw, sh);
    }

    // Draw walls
    ctx.fillStyle = "rgba(0, 80, 120, 0.8)";
    for (const wall of hole.walls) {
      const wx = toScreenX(wall.position.x - wall.size[0] / 2);
      const wz = toScreenZ(wall.position.z - wall.size[2] / 2);
      const ww = Math.max(wall.size[0] * scale, 1);
      const wh = Math.max(wall.size[2] * scale, 1);
      ctx.fillRect(wx, wz, ww, wh);
    }

    // Draw obstacles
    ctx.fillStyle = "rgba(255, 100, 50, 0.6)";
    for (const obs of hole.obstacles) {
      const ox = toScreenX(obs.position.x);
      const oz = toScreenZ(obs.position.z);
      if (obs.type === "bumper") {
        ctx.beginPath();
        ctx.arc(ox, oz, 3, 0, Math.PI * 2);
        ctx.fill();
      } else {
        ctx.fillRect(ox - 2, oz - 2, 4, 4);
      }
    }

    // Draw tee marker
    ctx.fillStyle = "#44ff88";
    ctx.beginPath();
    ctx.arc(toScreenX(tee.x), toScreenZ(tee.z), 4, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = "#ffffff";
    ctx.font = "8px monospace";
    ctx.textAlign = "center";
    ctx.fillText("T", toScreenX(tee.x), toScreenZ(tee.z) - 6);

    // Draw hole/cup marker
    const pulse = 0.5 + Math.sin(performance.now() * 0.005) * 0.5;
    ctx.fillStyle = `rgba(255, 255, 0, ${0.5 + pulse * 0.5})`;
    ctx.beginPath();
    ctx.arc(toScreenX(cup.x), toScreenZ(cup.z), 4, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = "#ffff00";
    ctx.lineWidth = 0.8;
    ctx.beginPath();
    ctx.arc(toScreenX(cup.x), toScreenZ(cup.z), 5 + pulse * 2, 0, Math.PI * 2);
    ctx.stroke();

    // Draw ball position
    if (this.ball.isActive) {
      const bx = toScreenX(this.ball.position.x);
      const bz = toScreenZ(this.ball.position.z);
      ctx.fillStyle = "#00ffff";
      ctx.beginPath();
      ctx.arc(bx, bz, 3, 0, Math.PI * 2);
      ctx.fill();

      // Ball glow
      ctx.fillStyle = "rgba(0, 255, 255, 0.2)";
      ctx.beginPath();
      ctx.arc(bx, bz, 6, 0, Math.PI * 2);
      ctx.fill();
    }

    // Label
    ctx.fillStyle = themeColor;
    ctx.font = "bold 9px monospace";
    ctx.textAlign = "left";
    ctx.fillText(`H${hole.index + 1}`, 4, 10);
  }
}

/**
 * Holo Golf VR — Browser Input Handler (Round 3 Overhaul)
 * Mouse/keyboard controls for desktop play.
 * Click + drag back from ball = aim + power, release = putt.
 * Right-drag orbits the camera around the ball. Scroll to zoom.
 * Integrates with XR controller camera orbit via xrInput.cameraOrbitDelta.
 */
import { World, Vector3 } from "@iwsdk/core";
import { PutterController } from "./putter";
import { BallController } from "./ball";
import { GameManager, GameState } from "./game";
import { UIManager } from "./ui";
import { XRInputHandler } from "./xrinput";
import { PowerMeter } from "./powermeter";
import { ScorecardOverlay } from "./scorecard";

const MAX_POWER = 10.0;

export class BrowserInputHandler {
  private world: World;
  private putter: PutterController;
  private ball: BallController;
  private game: GameManager;
  private ui: UIManager;
  private container: HTMLDivElement;
  private mouseDown = false;
  private powerMeter: PowerMeter;
  private scorecard: ScorecardOverlay;

  // XR input reference for camera orbit sync
  xrInput: XRInputHandler | null = null;

  // Camera orbit
  private cameraAngle = 0;
  private cameraElevation = 0.4;
  private cameraDistance = 5;
  private cameraTarget = new Vector3(0, 0, 0);
  private rightMouseDown = false;
  private lastRightX = 0;
  private lastRightY = 0;

  constructor(
    world: World,
    putter: PutterController,
    game: GameManager,
    ball: BallController,
    ui: UIManager,
    container: HTMLDivElement,
  ) {
    this.world = world;
    this.putter = putter;
    this.ball = ball;
    this.game = game;
    this.ui = ui;
    this.container = container;
    this.powerMeter = new PowerMeter();
    this.scorecard = new ScorecardOverlay(game);

    this.setupListeners();
  }

  private setupListeners() {
    this.container.addEventListener("mousedown", (e) => {
      if (e.button === 0) {
        if (
          this.game.state === GameState.AIMING &&
          !this.ui.isVisible() &&
          !this.scorecard.isVisible()
        ) {
          this.mouseDown = true;
          this.putter.startAim(e.clientX, e.clientY);
          this.powerMeter.show();
        }
      } else if (e.button === 2) {
        this.rightMouseDown = true;
        this.lastRightX = e.clientX;
        this.lastRightY = e.clientY;
      }
    });

    this.container.addEventListener("mousemove", (e) => {
      if (this.mouseDown) {
        this.putter.updateAim(e.clientX, e.clientY);
        this.powerMeter.update(this.putter.aimPower, MAX_POWER);
      }
      if (this.rightMouseDown) {
        const dx = e.clientX - this.lastRightX;
        const dy = e.clientY - this.lastRightY;
        this.cameraAngle -= dx * 0.005;
        this.cameraElevation = Math.max(0.1, Math.min(1.2, this.cameraElevation + dy * 0.003));
        this.lastRightX = e.clientX;
        this.lastRightY = e.clientY;
      }
    });

    window.addEventListener("mouseup", (e) => {
      if (e.button === 0 && this.mouseDown) {
        this.mouseDown = false;
        const hadPower = this.putter.aimPower > 0.1;
        this.putter.releaseAim();
        this.powerMeter.hide();
        if (hadPower) {
          this.game.onStroke();
        }
      }
      if (e.button === 2) {
        this.rightMouseDown = false;
      }
    });

    this.container.addEventListener("contextmenu", (e) => e.preventDefault());

    window.addEventListener("keydown", (e) => {
      switch (e.key.toLowerCase()) {
        case "r":
          if (this.game.state === GameState.AIMING) {
            this.game.resetBall();
          }
          break;
        case "tab":
          e.preventDefault();
          this.scorecard.toggle();
          break;
        case "escape":
          if (this.scorecard.isVisible()) {
            this.scorecard.hide();
          } else if (this.ui.isVisible()) {
            this.ui.showTitle();
          }
          break;
        case "enter":
        case " ":
          if (this.game.state === GameState.HOLE_COMPLETE) {
            this.game.skipToNextHole();
          } else if (this.game.state === GameState.COURSE_COMPLETE) {
            this.ui.showCourseComplete();
          }
          break;
      }
    });

    this.container.addEventListener("wheel", (e) => {
      this.cameraDistance = Math.max(2, Math.min(12, this.cameraDistance + e.deltaY * 0.005));
      e.preventDefault();
    }, { passive: false });
  }

  update(dt: number) {
    // Apply XR controller camera orbit delta
    if (this.xrInput) {
      const delta = this.xrInput.cameraOrbitDelta;
      if (delta.horizontal !== 0) {
        this.cameraAngle -= delta.horizontal;
      }
      if (delta.vertical !== 0) {
        this.cameraElevation = Math.max(0.1, Math.min(1.2, this.cameraElevation + delta.vertical));
      }
    }

    // Camera follows ball during gameplay
    const state = this.game.state;
    const isPlaying = state === GameState.AIMING || state === GameState.BALL_MOVING ||
                      state === GameState.HOLE_COMPLETE || state === GameState.PLAYING;

    if (isPlaying && this.ball.isActive) {
      this.cameraTarget.lerp(this.ball.position, dt * 3);
    } else if (isPlaying) {
      const hole = this.game.getCurrentHole();
      if (hole) {
        const mid = hole.teePosition.clone().add(hole.holePosition).multiplyScalar(0.5);
        this.cameraTarget.lerp(mid, dt * 2);
      }
    }

    // Compute orbit camera position
    let cam: any = null;
    if ((this.world as any).scene) {
      const scene = (this.world as any).scene;
      scene.traverse?.((child: any) => {
        if (!cam && child.isCamera) {
          cam = child;
        }
      });
    }

    if (cam) {
      const x = this.cameraTarget.x + Math.sin(this.cameraAngle) * this.cameraDistance * Math.cos(this.cameraElevation);
      const y = this.cameraTarget.y + this.cameraDistance * Math.sin(this.cameraElevation) + 0.5;
      const z = this.cameraTarget.z + Math.cos(this.cameraAngle) * this.cameraDistance * Math.cos(this.cameraElevation);

      cam.position.lerp(new Vector3(x, y, z), dt * 5);
      cam.lookAt(this.cameraTarget.x, this.cameraTarget.y + 0.1, this.cameraTarget.z);
    }
  }
}

/**
 * Holo Golf VR — HUD Manager (Round 3 Overhaul)
 * In-world heads-up display: hole info, scorecard, power meter.
 * New: stroke limit indicator, course-themed colors, improved mini-map layout.
 */
import {
  World,
  Group,
  Mesh,
  PlaneGeometry,
  MeshBasicMaterial,
  Color,
  DoubleSide,
  AdditiveBlending,
  BoxGeometry,
  CanvasTexture,
} from "@iwsdk/core";
import { GameManager, GameState, MAX_STROKES_PER_HOLE } from "./game";

// Course theme colors
const COURSE_COLORS = [
  { primary: "#00ffff", secondary: "#44ff88", accent: "#0088ff" },
  { primary: "#ff44aa", secondary: "#8844ff", accent: "#cc66ff" },
  { primary: "#ff6600", secondary: "#ffaa00", accent: "#ff4400" },
];

export class HUDManager {
  private world: World;
  private game: GameManager;
  private hudGroup: Group;

  private canvas: HTMLCanvasElement;
  private ctx2d: CanvasRenderingContext2D;
  private texture: CanvasTexture;
  private hudMesh: Mesh;
  private dirty = true;
  private lastState: GameState = GameState.LOADING;
  private lastStrokes = 0;

  constructor(world: World, game: GameManager) {
    this.world = world;
    this.game = game;
    this.hudGroup = new Group();

    this.canvas = document.createElement("canvas");
    this.canvas.width = 512;
    this.canvas.height = 256;
    this.ctx2d = this.canvas.getContext("2d")!;

    this.texture = new CanvasTexture(this.canvas);
    this.texture.needsUpdate = true;

    const hudGeo = new PlaneGeometry(1.6, 0.8);
    const hudMat = new MeshBasicMaterial({
      map: this.texture,
      transparent: true,
      opacity: 0.9,
      side: DoubleSide,
    });
    this.hudMesh = new Mesh(hudGeo, hudMat);
    this.hudMesh.position.set(0, 2.2, -3);
    this.hudGroup.add(this.hudMesh);

    world.scene.add(this.hudGroup);

    game.onStateChange(() => {
      this.dirty = true;
    });
  }

  update(dt: number) {
    if (this.dirty || this.game.state !== this.lastState || this.game.currentStrokes !== this.lastStrokes) {
      this.redraw();
      this.lastState = this.game.state;
      this.lastStrokes = this.game.currentStrokes;
      this.dirty = false;
    }
  }

  private getTheme() {
    return COURSE_COLORS[this.game.currentCourseIndex] || COURSE_COLORS[0];
  }

  private redraw() {
    const ctx = this.ctx2d;
    const w = this.canvas.width;
    const h = this.canvas.height;
    const theme = this.getTheme();

    ctx.clearRect(0, 0, w, h);

    // Background
    ctx.fillStyle = "rgba(0, 8, 20, 0.75)";
    ctx.fillRect(0, 0, w, h);

    // Border with course theme color
    ctx.strokeStyle = theme.primary;
    ctx.lineWidth = 2;
    ctx.strokeRect(2, 2, w - 4, h - 4);

    // Corner accents
    const cornerSize = 15;
    ctx.strokeStyle = theme.primary;
    ctx.lineWidth = 3;
    ctx.beginPath(); ctx.moveTo(2, cornerSize + 2); ctx.lineTo(2, 2); ctx.lineTo(cornerSize + 2, 2); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(w - cornerSize - 2, 2); ctx.lineTo(w - 2, 2); ctx.lineTo(w - 2, cornerSize + 2); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(2, h - cornerSize - 2); ctx.lineTo(2, h - 2); ctx.lineTo(cornerSize + 2, h - 2); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(w - cornerSize - 2, h - 2); ctx.lineTo(w - 2, h - 2); ctx.lineTo(w - 2, h - cornerSize - 2); ctx.stroke();

    const state = this.game.state;

    if (
      state === GameState.PLAYING ||
      state === GameState.AIMING ||
      state === GameState.BALL_MOVING ||
      state === GameState.HOLE_COMPLETE
    ) {
      const hole = this.game.getCurrentHole();
      if (!hole) return;

      // Hole name
      ctx.fillStyle = theme.primary;
      ctx.font = "bold 28px monospace";
      ctx.textAlign = "center";
      ctx.fillText(`HOLE ${hole.index + 1}`, w / 2, 40);

      // Hole name subtitle
      ctx.fillStyle = "#6688aa";
      ctx.font = "18px monospace";
      ctx.fillText(hole.name, w / 2, 65);

      // Par info
      ctx.fillStyle = "#ffff00";
      ctx.font = "bold 22px monospace";
      ctx.textAlign = "left";
      ctx.fillText(`PAR ${hole.par}`, 25, 110);

      // Strokes with limit indicator
      const strokeColor = this.game.currentStrokes >= MAX_STROKES_PER_HOLE - 2 ? "#ff4444"
        : this.game.currentStrokes >= MAX_STROKES_PER_HOLE - 4 ? "#ffaa00"
        : "#ffffff";
      ctx.fillStyle = strokeColor;
      ctx.fillText(`STROKES: ${this.game.currentStrokes}/${MAX_STROKES_PER_HOLE}`, 25, 140);

      // Score relative to par
      if (this.game.currentStrokes > 0) {
        const diff = this.game.currentStrokes - hole.par;
        const scoreName = this.game.getScoreName(this.game.currentStrokes, hole.par);
        ctx.fillStyle = diff <= 0 ? "#00ff88" : "#ff4488";
        ctx.font = "bold 20px monospace";
        ctx.textAlign = "right";
        ctx.fillText(scoreName, w - 25, 110);
      }

      // Total course score
      const totalStrokes = this.game.courseScore.totalStrokes + this.game.currentStrokes;
      ctx.fillStyle = "#8888cc";
      ctx.font = "16px monospace";
      ctx.textAlign = "right";
      ctx.fillText(`TOTAL: ${totalStrokes}`, w - 25, 140);

      // Mini scorecard (bottom)
      this.drawMiniScorecard(ctx, w, h, theme);

      // Hole complete overlay
      if (state === GameState.HOLE_COMPLETE) {
        const scoreName = this.game.getScoreName(this.game.currentStrokes, hole.par);
        ctx.fillStyle = "rgba(0, 20, 40, 0.6)";
        ctx.fillRect(50, 85, w - 100, 60);
        ctx.fillStyle = this.game.currentStrokes <= hole.par ? "#00ff88" : "#ffaa00";
        ctx.font = "bold 32px monospace";
        ctx.textAlign = "center";
        ctx.fillText(scoreName, w / 2, 125);
      }
    } else if (state === GameState.COURSE_COMPLETE) {
      ctx.fillStyle = "#ffff00";
      ctx.font = "bold 36px monospace";
      ctx.textAlign = "center";
      ctx.fillText("COURSE COMPLETE!", w / 2, 50);

      const score = this.game.courseScore;
      ctx.fillStyle = "#ffffff";
      ctx.font = "24px monospace";
      ctx.fillText(`Total: ${score.totalStrokes} strokes`, w / 2, 95);

      const totalPar = score.holes.reduce((s, h) => s + h.par, 0);
      const diff = score.totalStrokes - totalPar;
      ctx.fillStyle = diff <= 0 ? "#00ff88" : "#ff8844";
      ctx.fillText(
        diff === 0 ? "Even Par!" : diff < 0 ? `${diff} Under Par!` : `+${diff} Over Par`,
        w / 2,
        130,
      );

      const holeInOnes = score.holes.filter((h) => h.holeInOne).length;
      if (holeInOnes > 0) {
        ctx.fillStyle = "#ffff00";
        ctx.font = "20px monospace";
        ctx.fillText(`⭐ ${holeInOnes} Hole-in-One${holeInOnes > 1 ? "s" : ""}!`, w / 2, 165);
      }

      ctx.fillStyle = "#6688aa";
      ctx.font = "16px monospace";
      ctx.fillText("Click or press A to return to menu", w / 2, h - 25);
    }

    this.texture.needsUpdate = true;
  }

  private drawMiniScorecard(ctx: CanvasRenderingContext2D, w: number, h: number, theme: any) {
    const score = this.game.courseScore;
    const startX = 20;
    const startY = h - 70;
    const cellW = (w - 40) / 9;

    // Hole numbers
    ctx.fillStyle = "#445566";
    ctx.font = "11px monospace";
    ctx.textAlign = "center";
    for (let i = 0; i < 9; i++) {
      const x = startX + i * cellW + cellW / 2;
      ctx.fillText(`${i + 1}`, x, startY);
    }

    // Pars
    ctx.fillStyle = "#667788";
    for (let i = 0; i < 9; i++) {
      const x = startX + i * cellW + cellW / 2;
      ctx.fillText(`P${score.holes[i].par}`, x, startY + 15);
    }

    // Scores
    for (let i = 0; i < 9; i++) {
      const holeScore = score.holes[i];
      if (holeScore.strokes === 0 && i > this.game.currentHoleIndex) continue;

      const strokes = i === this.game.currentHoleIndex && holeScore.strokes === 0
        ? this.game.currentStrokes
        : holeScore.strokes;

      if (strokes === 0) continue;

      const diff = strokes - holeScore.par;
      ctx.fillStyle =
        strokes === 1 ? "#ffff00" : diff < 0 ? "#00ff88" : diff === 0 ? "#ffffff" : "#ff6644";
      ctx.font = "bold 14px monospace";
      const x = startX + i * cellW + cellW / 2;
      ctx.fillText(`${strokes}`, x, startY + 35);
    }

    // Current hole indicator
    const currentX = startX + this.game.currentHoleIndex * cellW;
    ctx.strokeStyle = theme.primary;
    ctx.lineWidth = 1;
    ctx.strokeRect(currentX, startY - 8, cellW, 50);
  }
}

/**
 * Holo Golf VR — Power Meter
 * Visual power indicator shown while aiming in browser mode.
 */

export class PowerMeter {
  private container: HTMLDivElement;
  private bar: HTMLDivElement;
  private label: HTMLDivElement;
  private visible = false;

  constructor() {
    this.container = document.createElement("div");
    this.container.style.cssText = `
      position: fixed; bottom: 30px; left: 50%; transform: translateX(-50%);
      width: 300px; height: 24px; background: rgba(0, 10, 20, 0.85);
      border: 1px solid #003344; display: none; z-index: 150;
      font-family: 'Courier New', monospace;
    `;

    this.bar = document.createElement("div");
    this.bar.style.cssText = `
      width: 0%; height: 100%;
      background: linear-gradient(90deg, #00ff88, #ffff00, #ff4444);
      transition: width 0.05s ease;
    `;
    this.container.appendChild(this.bar);

    this.label = document.createElement("div");
    this.label.style.cssText = `
      position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%);
      color: #ffffff; font-size: 11px; letter-spacing: 2px;
      text-shadow: 0 0 5px #000;
    `;
    this.container.appendChild(this.label);

    document.body.appendChild(this.container);
  }

  show() {
    this.visible = true;
    this.container.style.display = "block";
  }

  hide() {
    this.visible = false;
    this.container.style.display = "none";
  }

  update(power: number, maxPower: number) {
    if (!this.visible) return;
    const pct = Math.min((power / maxPower) * 100, 100);
    this.bar.style.width = `${pct}%`;

    if (pct < 30) {
      this.label.textContent = "GENTLE";
    } else if (pct < 60) {
      this.label.textContent = "MEDIUM";
    } else if (pct < 85) {
      this.label.textContent = "STRONG";
    } else {
      this.label.textContent = "FULL POWER";
    }
  }
}

/**
 * Holo Golf VR — Teleporter Pad
 * Interactive teleport pads that warp the ball between locations.
 * Also handles wind zone and ice surface behaviors.
 */
import {
  Mesh,
  CylinderGeometry,
  MeshBasicMaterial,
  MeshStandardMaterial,
  Color,
  AdditiveBlending,
  Group,
  RingGeometry,
  DoubleSide,
  PointLight,
  TorusGeometry,
  Vector3,
} from "@iwsdk/core";

export interface TeleportPad {
  group: Group;
  position: Vector3;
  targetPosition: Vector3;
  radius: number;
  active: boolean;
  cooldown: number;
}

export function createTeleportPad(
  pos: Vector3,
  target: Vector3,
  color = 0x8844ff,
): TeleportPad {
  const group = new Group();
  group.position.copy(pos);

  // Base ring
  const baseGeo = new CylinderGeometry(0.12, 0.12, 0.01, 24);
  const baseMat = new MeshBasicMaterial({
    color,
    transparent: true,
    opacity: 0.4,
    blending: AdditiveBlending,
  });
  group.add(new Mesh(baseGeo, baseMat));

  // Inner ring
  const innerGeo = new RingGeometry(0.04, 0.08, 16);
  const innerMat = new MeshBasicMaterial({
    color,
    transparent: true,
    opacity: 0.6,
    side: DoubleSide,
    blending: AdditiveBlending,
  });
  const inner = new Mesh(innerGeo, innerMat);
  inner.rotation.x = -Math.PI / 2;
  inner.position.y = 0.01;
  group.add(inner);

  // Orbiting particles
  for (let i = 0; i < 4; i++) {
    const angle = (i / 4) * Math.PI * 2;
    const dotGeo = new CylinderGeometry(0.01, 0.01, 0.03, 4);
    const dotMat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.8,
      blending: AdditiveBlending,
    });
    const dot = new Mesh(dotGeo, dotMat);
    dot.position.set(Math.cos(angle) * 0.1, 0.05, Math.sin(angle) * 0.1);
    group.add(dot);
  }

  // Vertical beam
  const beamGeo = new CylinderGeometry(0.008, 0.008, 0.4, 4);
  const beamMat = new MeshBasicMaterial({
    color,
    transparent: true,
    opacity: 0.25,
    blending: AdditiveBlending,
  });
  const beam = new Mesh(beamGeo, beamMat);
  beam.position.y = 0.2;
  group.add(beam);

  // Light
  const light = new PointLight(color, 0.4, 2);
  light.position.y = 0.1;
  group.add(light);

  return {
    group,
    position: pos.clone(),
    targetPosition: target.clone(),
    radius: 0.12,
    active: true,
    cooldown: 0,
  };
}

export interface WindZone {
  group: Group;
  position: Vector3;
  direction: Vector3;
  force: number;
  size: Vector3;
}

export function createWindZone(
  pos: Vector3,
  dir: Vector3,
  force: number,
  size: Vector3,
): WindZone {
  const group = new Group();
  group.position.copy(pos);

  // Visual: directional arrows/particles
  const arrowCount = 5;
  for (let i = 0; i < arrowCount; i++) {
    const t = i / arrowCount;
    const arrowGeo = new CylinderGeometry(0, 0.02, 0.06, 3);
    const arrowMat = new MeshBasicMaterial({
      color: 0x44aaff,
      transparent: true,
      opacity: 0.3 + t * 0.2,
      blending: AdditiveBlending,
    });
    const arrow = new Mesh(arrowGeo, arrowMat);
    arrow.position.set(
      dir.x * t * size.x * 0.4,
      0.03,
      dir.z * t * size.z * 0.4,
    );
    // Point arrow in wind direction
    arrow.rotation.x = Math.PI;
    if (dir.z < 0) arrow.rotation.z = Math.PI;
    group.add(arrow);
  }

  return { group, position: pos.clone(), direction: dir.clone().normalize(), force, size };
}

export interface IceSurface {
  group: Group;
  position: Vector3;
  size: Vector3;
  friction: number;
}

export function createIceSurface(pos: Vector3, size: Vector3): IceSurface {
  const group = new Group();
  group.position.copy(pos);

  // Ice-like surface overlay
  const iceGeo = new CylinderGeometry(size.x / 2, size.x / 2, 0.005, 16);
  const iceMat = new MeshStandardMaterial({
    color: 0x88ccff,
    emissive: new Color(0x4488cc),
    emissiveIntensity: 0.5,
    metalness: 1.0,
    roughness: 0.0,
    transparent: true,
    opacity: 0.4,
  });
  const ice = new Mesh(iceGeo, iceMat);
  ice.position.y = 0.003;
  group.add(ice);

  return { group, position: pos.clone(), size, friction: 0.995 };
}

/**
 * Holo Golf VR — Practice Mode
 * Allows replaying individual holes for practice without affecting course scores.
 * Accessible from the course select screen.
 */
import { GameManager, GameState } from "./game";
import { AudioManager } from "./audio";

export class PracticeMode {
  private overlay: HTMLDivElement;
  private game: GameManager;
  private audio: AudioManager;
  private visible = false;
  private selectedCourse = 0;
  private practiceActive = false;
  private bestPracticeScores: Map<string, number> = new Map();

  constructor(game: GameManager, audio: AudioManager) {
    this.game = game;
    this.audio = audio;

    this.overlay = document.createElement("div");
    this.overlay.id = "practice-overlay";
    this.overlay.style.cssText = `
      position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%);
      width: 520px; max-width: 92vw; max-height: 80vh;
      padding: 25px; overflow-y: auto;
      background: rgba(0, 10, 25, 0.95);
      border: 2px solid #44ff88;
      font-family: 'Courier New', monospace;
      color: #ffffff;
      z-index: 250;
      display: none;
      pointer-events: auto;
    `;
    document.body.appendChild(this.overlay);

    this.loadPracticeScores();
  }

  show(courseIndex: number) {
    this.selectedCourse = courseIndex;
    this.visible = true;
    this.redraw();
    this.overlay.style.display = "block";
  }

  hide() {
    this.visible = false;
    this.overlay.style.display = "none";
  }

  isVisible(): boolean {
    return this.visible;
  }

  isPracticeActive(): boolean {
    return this.practiceActive;
  }

  endPractice() {
    this.practiceActive = false;
  }

  private redraw() {
    const courseManager = this.game.courseManager;
    const course = courseManager.getCourse(this.selectedCourse);
    const themeColors = ["#00ffff", "#ff44aa", "#ff6600"];
    const color = themeColors[this.selectedCourse] || themeColors[0];

    let html = `
      <div style="text-align: center; margin-bottom: 15px;">
        <div style="font-size: 20px; color: ${color}; letter-spacing: 3px;">PRACTICE MODE</div>
        <div style="font-size: 13px; color: #4488aa;">${course.name}</div>
        <div style="font-size: 10px; color: #334455; margin-top: 4px;">SELECT A HOLE TO PRACTICE</div>
      </div>
      <div style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px;">
    `;

    for (let i = 0; i < course.holes.length; i++) {
      const hole = course.holes[i];
      const key = `practice_${this.selectedCourse}_${i}`;
      const best = this.bestPracticeScores.get(key);
      const bestText = best ? `Best: ${best}` : "—";

      html += `
        <div id="practice-hole-${i}" style="
          padding: 12px; text-align: center;
          border: 1px solid ${color}40;
          background: rgba(0, 15, 30, 0.8);
          cursor: pointer;
          transition: all 0.2s ease;
        ">
          <div style="font-size: 18px; color: ${color}; font-weight: bold;">${i + 1}</div>
          <div style="font-size: 10px; color: #6688aa; margin-top: 4px;">${hole.name}</div>
          <div style="font-size: 10px; color: #445566; margin-top: 2px;">Par ${hole.par}</div>
          <div style="font-size: 9px; color: #334455; margin-top: 2px;">${bestText}</div>
        </div>
      `;
    }

    html += `
      </div>
      <div style="text-align: center; margin-top: 15px;">
        <button id="practice-close" style="
          background: transparent; border: 1px solid #445566;
          color: #6688aa; font-family: 'Courier New', monospace;
          font-size: 14px; padding: 8px 24px; cursor: pointer;
          letter-spacing: 2px;
        ">← BACK</button>
      </div>
    `;

    this.overlay.innerHTML = html;

    for (let i = 0; i < course.holes.length; i++) {
      this.overlay.querySelector(`#practice-hole-${i}`)?.addEventListener("click", () => {
        this.audio.playMenuSelect();
        this.startPractice(i);
      });
    }

    this.overlay.querySelector("#practice-close")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.hide();
    });
  }

  private startPractice(holeIndex: number) {
    this.practiceActive = true;
    this.hide();

    // Use game manager's startCourse, then load specific hole
    this.game.startPracticeHole(this.selectedCourse, holeIndex);
  }

  recordPracticeScore(courseIndex: number, holeIndex: number, strokes: number) {
    const key = `practice_${courseIndex}_${holeIndex}`;
    const best = this.bestPracticeScores.get(key);
    if (!best || strokes < best) {
      this.bestPracticeScores.set(key, strokes);
      this.savePracticeScores();
    }
  }

  private loadPracticeScores() {
    try {
      const data = localStorage.getItem("holo-golf-practice");
      if (data) {
        const parsed = JSON.parse(data);
        Object.entries(parsed).forEach(([k, v]) => this.bestPracticeScores.set(k, v as number));
      }
    } catch {}
  }

  private savePracticeScores() {
    try {
      const obj: Record<string, number> = {};
      this.bestPracticeScores.forEach((v, k) => (obj[k] = v));
      localStorage.setItem("holo-golf-practice", JSON.stringify(obj));
    } catch {}
  }
}

